BEGIN;

DELETE FROM route_waypoints WHERE route_code = 'SMX';
DELETE FROM service_routes WHERE route_code = 'SMX';

VALUES ('SMX', 'SMX', 'SMX service imported from route waypoint files.', TRUE)
ON CONFLICT (code) DO UPDATE
SET
  name = EXCLUDED.name,
  description = EXCLUDED.description,
  is_active = TRUE;

VALUES ('SMX', 'SMX', 
'SMX - CNSHA/CNTAO/KRPUS/MXZLO/CNSHA'
, 'ROUND', 'SMX route imported from waypoint files.', TRUE);


COMMIT;
